data class Circle(val radius: Double)
val area = Circle(5.0).run {
    val r = radius
    3.14159 * r * r
}
println(area)

val list = mutableListOf<Int>()
    .apply { add(1); add(2); add(3) }
    .apply { add(4); add(5) }
println(list.size)

val number = 42
val description: String = number.let {
    when {
        it < 0 -> "negative"
        it == 0 -> "zero"
        else -> "positive"
    }
}
println(description)

val original = mutableListOf(1, 2, 3)
val fromAlso = original.also { it.add(4) }
val fromLet  = original.let  { it.size }
println(fromAlso === original)
println(fromLet)
